(function(){
const baseDetect=detect,baseUpload=upload;
let running=false,lastFingerprint='',wakeLock=null,memoryTimer=null,memorySamples=[],runStarted=0,retries=0;
const units=new Set(['ขวด','ชิ้น','แพ็ค','กล่อง','ลัง','ซอง','ถุง','ชุด','ด้าม']);
async function fingerprint(file){if(!file)return'';const head=await file.slice(0,65536).arrayBuffer(),tail=await file.slice(Math.max(0,file.size-65536)).arrayBuffer(),all=new Uint8Array(head.byteLength+tail.byteLength+24);all.set(new Uint8Array(head),0);all.set(new Uint8Array(tail),head.byteLength);new DataView(all.buffer).setFloat64(all.length-24,file.size);new DataView(all.buffer).setFloat64(all.length-16,file.lastModified);const d=await crypto.subtle.digest('SHA-256',all);return[...new Uint8Array(d)].map(x=>x.toString(16).padStart(2,'0')).join('')}
async function lockWake(){try{wakeLock=await navigator.wakeLock?.request('screen')}catch{}}
async function unlockWake(){try{await wakeLock?.release()}catch{}wakeLock=null}
function sampleMemory(){const m=performance.memory;if(!m)return;memorySamples.push({t:Math.round(performance.now()-runStarted),used:m.usedJSHeapSize,total:m.totalJSHeapSize,limit:m.jsHeapSizeLimit});if(memorySamples.length>2400)memorySamples.shift()}
function gate(report){const cards=Array.isArray(report?.cards)?report.cards:[],ids=cards.map(x=>x.card_id),classTotal=Object.values(report?.class_counts||{}).reduce((s,n)=>s+Number(n||0),0),errors=[];if(!cards.length||report.total!==cards.length||items.length!==cards.length)errors.push('count_mismatch');if(new Set(ids).size!==ids.length)errors.push('duplicate_card_id');if(classTotal!==cards.length)errors.push('class_count_mismatch');for(const c of cards){if(!c.grid_pass)errors.push(`${c.card_id}:grid`);if(c.detection_status!=='auto_ok')errors.push(`${c.card_id}:promo`);if(c.price_status!=='auto_ok'||!(Number(c.base_unit_price)>0)||!units.has(c.unit_label))errors.push(`${c.card_id}:price`);if(c.title_status!=='auto_ok'||!String(c.promo_title||'').trim())errors.push(`${c.card_id}:title`);if(c.master_status!=='auto_ok'||!/^[0-9a-f-]{36}$/i.test(c.master_product_id||'')||c.master_provisional)errors.push(`${c.card_id}:master`);if(c.price_group_conflict)errors.push(`${c.card_id}:group_price`);if(!String(c.detected_function_label||'').trim())errors.push(`${c.card_id}:function`)}return{pass:errors.length===0&&report.need_review===0&&report.auto_ok===cards.length,total:cards.length,error_count:errors.length,errors:errors.slice(0,100)}}
function csv(report){const cols=['card_id','class_id','page_no','card_no','row_layout','grid_pass','detection_status','detected_function_label','promo_title','base_unit_price','unit_label','price_status','title_status','master_status','master_product_id','master_is_new','master_provisional','price_group_support','price_group_conflict','confidence'];const esc=v=>`"${String(v??'').replace(/"/g,'""')}"`;return'\ufeff'+[cols.join(','),...(report.cards||[]).map(r=>cols.map(k=>esc(r[k])).join(','))].join('\n')}
function download(name,text,type){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([text],{type}));a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1500)}
function addControls(){if($('exportAuditCsv'))return;const csvBtn=document.createElement('button');csvBtn.id='exportAuditCsv';csvBtn.type='button';csvBtn.className='btn gray';csvBtn.textContent='ดาวน์โหลดผลตรวจ CSV';csvBtn.onclick=()=>lastReport?download(`promo-audit-${Date.now()}.csv`,csv(lastReport),'text/csv;charset=utf-8'):alert('ตรวจไฟล์ก่อน');$('clear').insertAdjacentElement('beforebegin',csvBtn);const box=document.createElement('div');box.id='runtimeProof';box.className='note';box.style.marginTop='10px';box.textContent='หลักฐานเครื่อง: ยังไม่ได้รัน';document.querySelector('.drop').appendChild(box)}
function runtimeText(report){const used=memorySamples.map(x=>x.used),peak=used.length?Math.max(...used):0,sec=((performance.now()-runStarted)/1000).toFixed(1),g=report?.release_gate;return`หลักฐานเครื่อง: ${/Android/i.test(navigator.userAgent)?'Android':'Browser'} | เวลา ${sec} วิ | retry ${retries} | RAM JS สูงสุด ${peak?Math.round(peak/1048576)+' MB':'อ่านค่าไม่ได้'} | Gate ${g?.pass?'PASS':'BLOCK'}${g?.error_count?' ('+g.error_count+' จุด)':''}`}
async function runOnce(){lastFingerprint=await fingerprint(sourceFile);return baseDetect()}
detect=async function(){if(running)throw Error('กำลังตรวจอยู่');running=true;runStarted=performance.now();memorySamples=[];retries=0;await lockWake();memoryTimer=setInterval(sampleMemory,1000);sampleMemory();window.onbeforeunload=()=>running?'กำลัง OCR อยู่ การออกจากหน้านี้จะทำให้ผลหาย':undefined;try{let report;try{report=await runOnce()}catch(e){if(!/worker|memory|abort|terminated|recognize|wasm/i.test(String(e?.message||e)))throw e;retries=1;log('OCR Worker มีปัญหา — ระบบลดเหลือ 1 Worker และเริ่มตรวจใหม่อัตโนมัติ','warn');if($('workers'))$('workers').value='1';for(const w of ocrWorkers)try{await w.terminate()}catch{}ocrWorkers=[];report=await runOnce()}const nowFingerprint=await fingerprint(sourceFile);if(nowFingerprint!==lastFingerprint)throw Error('source_file_changed_during_run');report.runtime={user_agent:navigator.userAgent,device_memory_gb:Number(navigator.deviceMemory||0)||null,hardware_concurrency:Number(navigator.hardwareConcurrency||0)||null,retries,duration_ms:Math.round(performance.now()-runStarted),memory_samples:memorySamples,peak_js_heap_bytes:memorySamples.length?Math.max(...memorySamples.map(x=>x.used)):null,source_fingerprint:lastFingerprint};report.release_gate=gate(report);lastReport=report;$('upload').disabled=!report.release_gate.pass;try{localStorage.setItem(`promo-v2-last-audit:${lastFingerprint}`,JSON.stringify({...report,runtime:{...report.runtime,memory_samples:undefined}}))}catch{}$('runtimeProof').textContent=runtimeText(report);st(report.release_gate.pass?`ตรวจครบ ${report.total} ใบ — Gate PASS พร้อมเผยแพร่`:`ตรวจครบ ${report.total} ใบ — Gate BLOCK ${report.release_gate.error_count} จุด ต้องแก้ก่อน`);return report}finally{running=false;clearInterval(memoryTimer);memoryTimer=null;window.onbeforeunload=null;await unlockWake()}};
upload=async function(){if(running)return alert('รอการตรวจให้เสร็จก่อน');if(!lastReport?.release_gate?.pass)return alert('Release Gate ยังไม่ผ่าน ระบบไม่อนุญาตให้เผยแพร่');const current=await fingerprint(sourceFile);if(!current||current!==lastReport.runtime?.source_fingerprint)return alert('ไฟล์เปลี่ยนหลังตรวจ กรุณาตรวจใหม่');return baseUpload()};
addControls();
window.PromoRuntimeGate={version:'v1',gate,fingerprint,csv};
})();